document.addEventListener("DOMContentLoaded",async()=>{const t=document.getElementById("homeArtistsGrid");if(t){t.innerHTML='<p class="muted">Loading artists...</p>';try{const a=await fetchArtistsFromSanity(3);if(!a||!a.length)return void(t.innerHTML='<p class="muted">No artists available.</p>');t.innerHTML=a.map(t=>{const a=t.slug||t._id,n=t.image?.asset?.url||null,s=n?"function"==typeof window.sanityImgUrl?window.sanityImgUrl(n,{w:300,h:300,fit:"crop",q:80}):n:"images/artists/placeholder.jpg";return`\n        <a class="artist-card"\n           href="artists/artist.html?artist=${encodeURIComponent(a)}">\n\n          <div class="artist-avatar"\n               style="background-image:url('${s}')"></div>\n\n          <h3 class="artist-name">\n            <img src="images/icon.jpg" class="flag-icon" alt="">\n            <span>${t.name}</span>\n          </h3>\n\n          ${t.style?`<p class="artist-style">${t.style}</p>`:""}\n        </a>\n      `}).join("")}catch(a){console.error("❌ Failed to load artists on home page",a),t.innerHTML='<p class="muted">Failed to load artists.</p>'}}});